// src/pages/Upload.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Upload.css';
import { coursesData } from '../data/coursesData';

const Upload = () => {
  const navigate = useNavigate();
  
  // User state
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  
  // Upload states
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [backendCourses, setBackendCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(false);
  const [subjects, setSubjects] = useState([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploadStatus, setUploadStatus] = useState(null);
  
  // Complete form data
  const [formData, setFormData] = useState({
    // Basic info
    title: '',
    description: '',
    
    // Academic info
    course_id: '',
    branch: '',
    year: '',
    semester: '',
    subject_name: '',
    subject_code: '',
    
    // Material info
    material_type: 'notes',
    tags: ''
  });

  // Available options
  const yearOptions = ['1', '2', '3', '4'];
  const semesterOptions = ['1', '2', '3', '4', '5', '6', '7', '8'];
  
  const materialTypes = [
    { value: 'notes', label: '📄 Notes' },
    { value: 'pyq', label: '📝 Previous Year Questions (PYQ)' },
    { value: 'syllabus', label: '📋 Syllabus' },
    { value: 'lab', label: '🔬 Lab Manuals' },
    { value: 'assignment', label: '📝 Assignments' },
    { value: 'presentation', label: '📊 Presentations' },
    { value: 'important', label: '❓ Important Questions' },
    { value: 'project', label: '📁 Project Report' },
    { value: 'book', label: '📚 Reference Book' }
  ];

  useEffect(() => {
    // Check authentication
    const savedUser = localStorage.getItem('study_portal_user');
    const savedToken = localStorage.getItem('study_portal_token');
    
    if (savedUser && savedToken) {
      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        setIsAuthenticated(true);
        
      } catch (error) {
        console.error('Error parsing user:', error);
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
    
    // Load courses from backend
    fetchCoursesFromBackend();
    
    // Add KIET courses if not exists
    setTimeout(() => {
      addKietCourses();
    }, 2000);
  }, [navigate]);

  // Update subjects when course changes
  useEffect(() => {
    updateSubjects();
  }, [formData.course_id, formData.year, formData.semester]);

  const addKietCourses = async () => {
    try {
      const token = localStorage.getItem('study_portal_token');
      const response = await fetch('http://localhost:5000/api/add-kiet-courses', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });
      
      if (response.ok) {
        const data = await response.json();
        console.log('KIET courses added:', data.message);
        fetchCoursesFromBackend(); // Refresh courses
      }
    } catch (error) {
      console.log('KIET courses may already exist');
    }
  };

  const fetchCoursesFromBackend = async () => {
    try {
      setLoadingCourses(true);
      const response = await fetch('http://localhost:5000/api/courses');
      
      if (response.ok) {
        const data = await response.json();
        setBackendCourses(data.courses || []);
        console.log('Backend courses loaded:', data.courses.length);
      } else {
        console.warn('Could not fetch courses from backend');
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoadingCourses(false);
    }
  };

  const updateSubjects = () => {
    const { course_id, year, semester } = formData;
    
    let availableSubjects = [];
    
    // If we have course ID, get subjects from coursesData
    if (course_id) {
      // Get course info from backend
      const selectedCourse = backendCourses.find(c => c.id === parseInt(course_id));
      
      if (selectedCourse) {
        // Try to get subjects based on course name
        let subjectsFromDB = [];
        
        // Map backend course name to coursesData
        const courseMap = {
          'B.Tech': '1',
          'BCA': '2', 
          'BBA': '3',
          'MCA': '4',
          'MBA': '5'
        };
        
        Object.keys(courseMap).forEach(courseName => {
          if (selectedCourse.name.includes(courseName)) {
            const courseId = courseMap[courseName];
            const yearNum = parseInt(year) || 1;
            const semNum = parseInt(semester) || 1;
            
            // Get subjects from coursesData
            try {
              const course = coursesData[courseId];
              if (course && course.years[yearNum] && course.years[yearNum].semesters[semNum]) {
                subjectsFromDB = course.years[yearNum].semesters[semNum].map(subject => ({
                  name: subject.name,
                  code: subject.code,
                  display: `${subject.name} (${subject.code})`
                }));
              }
            } catch (error) {
              console.log('Error getting subjects:', error);
            }
          }
        });
        
        if (subjectsFromDB.length > 0) {
          availableSubjects = subjectsFromDB.map(sub => sub.display);
        }
      }
    }
    
    // Always add custom option
    availableSubjects.push('Other - Custom Subject');
    
    setSubjects(availableSubjects);
    
    // Auto-select first subject if none selected
    if (!formData.subject_name && availableSubjects.length > 0) {
      setFormData(prev => ({ ...prev, subject_name: availableSubjects[0] }));
    }
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      // Validate file size (10MB)
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      
      // Validate file type
      const allowedTypes = [
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-powerpoint',
        'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'text/plain',
        'image/jpeg',
        'image/png'
      ];
      
      if (!allowedTypes.includes(selectedFile.type)) {
        alert('❌ File type not supported. Please upload PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, or PNG files.');
        e.target.value = '';
        return;
      }
      
      setFile(selectedFile);
      
      // Auto-fill title from filename if empty
      if (!formData.title.trim()) {
        const fileName = selectedFile.name.replace(/\.[^/.]+$/, "");
        setFormData(prev => ({ ...prev, title: fileName }));
      }
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleUpload = async () => {
    // Validation
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    
    if (!formData.course_id) {
      alert('❌ Please select course');
      return;
    }

    setUploading(true);
    setUploadProgress(0);
    setUploadStatus(null);

    try {
      const token = localStorage.getItem('study_portal_token');
      
      if (!token) {
        throw new Error('Authentication token missing. Please login again.');
      }

      // Prepare FormData
      const uploadData = new FormData();
      
      // Add file
      uploadData.append('file', file);
      
      // Add all form data
      Object.keys(formData).forEach(key => {
        if (formData[key]) {
          uploadData.append(key, formData[key]);
        }
      });
      
      // Extract subject code if available
      const subjectMatch = formData.subject_name.match(/\(([^)]+)\)/);
      if (subjectMatch && subjectMatch[1]) {
        uploadData.append('subject_code', subjectMatch[1]);
      }
      
      // Get course info for logging
      const selectedCourse = backendCourses.find(c => c.id === parseInt(formData.course_id));
      
      console.log('Uploading details:', {
        title: formData.title,
        course: selectedCourse?.name,
        course_id: formData.course_id,
        year: formData.year,
        semester: formData.semester,
        subject: formData.subject_name,
        type: formData.material_type,
        file: file.name,
        file_size: (file.size / 1024 / 1024).toFixed(2) + ' MB'
      });

      // Simulate progress
      const progressInterval = setInterval(() => {
        setUploadProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return prev;
          }
          return prev + 10;
        });
      }, 200);

      // Send to backend
      const response = await fetch('http://localhost:5000/api/upload/complete', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          // Don't set Content-Type for FormData
        },
        body: uploadData,
      });

      clearInterval(progressInterval);
      setUploadProgress(100);

      const result = await response.json();
      
      if (response.ok) {
        // Success
        setUploadStatus({
          type: 'success',
          message: result.message || '✅ File uploaded successfully!',
          details: result.note,
          nextSteps: result.next_steps || []
        });
        
        // Reset form after 3 seconds
        setTimeout(() => {
          resetForm();
          setUploadStatus(null);
          setUploadProgress(0);
        }, 3000);
        
      } else {
        // Error
        setUploadStatus({
          type: 'error',
          message: `❌ Upload failed: ${result.error || 'Server error'}`,
          details: null
        });
      }
      
    } catch (error) {
      console.error('Upload error:', error);
      
      if (error.name === 'TypeError' && error.message.includes('fetch')) {
        setUploadStatus({
          type: 'error',
          message: '❌ Network Error: Cannot connect to backend at http://localhost:5000'
        });
      } else {
        setUploadStatus({
          type: 'error',
          message: `❌ Upload Error: ${error.message}`
        });
      }
    } finally {
      setUploading(false);
    }
  };

  const resetForm = () => {
    setFile(null);
    setFormData({
      title: '',
      description: '',
      course_id: '',
      branch: '',
      year: '',
      semester: '',
      subject_name: '',
      subject_code: '',
      material_type: 'notes',
      tags: ''
    });
    const fileInput = document.getElementById('fileInput');
    if (fileInput) fileInput.value = '';
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    navigate('/login');
  };

  // Show loading while checking authentication
  if (!user && isAuthenticated === false) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading authentication...</p>
      </div>
    );
  }

  return (
    <div className="upload-container">
      {/* Header */}
      <div className="upload-header-row">
        <header className="upload-header">
          <h1 className="upload-title">📤 Upload Study Materials</h1>
          <p className="upload-subtitle">
            Share your notes, PYQs, and study materials with KIET community
          </p>
        </header>
        
        <button onClick={handleLogout} className="logout-button">
          Logout
        </button>
      </div>

      {/* User Info */}
      <div className="user-info">
        <div className="user-avatar">
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div className="user-details">
          <p className="user-name">
            Uploading as: <span>{user?.name || 'User'}</span>
          </p>
          <p className="user-meta">
            {user?.branch || 'Branch'} • Semester {user?.semester || 'Semester'}
          </p>
          <p className="user-email">
            {user?.email || 'Email not provided'}
          </p>
        </div>
      </div>

      {/* File Upload Section */}
      <div className="upload-box">
        <input
          type="file"
          id="fileInput"
          className="file-input"
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
        />
        <label htmlFor="fileInput" className="upload-label">
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div className="file-info">
            <div className="file-info-row">
              <span className="file-info-label">📄 File:</span>
              <span className="file-info-value">{file.name}</span>
            </div>
            <div className="file-info-row">
              <span className="file-info-label">📏 Size:</span>
              <span className="file-info-value">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
            </div>
            <div className="file-info-row">
              <span className="file-info-label">📝 Type:</span>
              <span className="file-info-value">{file.type}</span>
            </div>
          </div>
        )}
        
        <p className="file-types">
          📎 <strong>Supported Formats:</strong> PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ <strong>Maximum file size:</strong> 10MB
        </p>
      </div>

      {/* Progress Bar */}
      {uploadProgress > 0 && (
        <div className="progress-container">
          <div className="progress-bar">
            <div 
              className="progress-fill"
              style={{ width: `${uploadProgress}%` }}
            ></div>
          </div>
          <div className="progress-text">
            Uploading: {uploadProgress}%
          </div>
        </div>
      )}

      {/* Status Message */}
      {uploadStatus && (
        <div className={`status-message ${uploadStatus.type}`}>
          <div className="status-icon">
            {uploadStatus.type === 'success' ? '✅' : '❌'}
          </div>
          <div className="status-content">
            <strong>{uploadStatus.message}</strong>
            {uploadStatus.details && (
              <div className="status-details">
                <p>Title: {uploadStatus.details.title}</p>
                <p>Course: {uploadStatus.details.course_name}</p>
                <p>Status: {uploadStatus.details.status}</p>
              </div>
            )}
            {uploadStatus.nextSteps && uploadStatus.nextSteps.length > 0 && (
              <div className="next-steps">
                <p><strong>Next Steps:</strong></p>
                <ul>
                  {uploadStatus.nextSteps.map((step, index) => (
                    <li key={index}>{step}</li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Upload Form */}
      <div className="upload-form">
        <h3 className="form-section-title">📄 Material Details</h3>
        
        {/* Title */}
        <div className="form-group">
          <label className="form-label">
            Title <span className="required">*</span>
            <small>(Descriptive title of your material)</small>
          </label>
          <input
            type="text"
            name="title"
            placeholder="e.g., Complete Data Structures Notes, Operating Systems PYQ 2023"
            value={formData.title}
            onChange={handleInputChange}
            className="form-input"
            required
          />
        </div>

        {/* Description */}
        <div className="form-group">
          <label className="form-label">
            Description <small>(Optional details about the material)</small>
          </label>
          <textarea
            name="description"
            placeholder="Describe what's included in this material, important topics covered, etc."
            value={formData.description}
            onChange={handleInputChange}
            className="form-textarea"
            rows="3"
          />
        </div>

        <h3 className="form-section-title">🎓 Academic Details</h3>
        
        {/* Course Selection */}
        <div className="form-group">
          <label className="form-label">
            Course <span className="required">*</span>
            <small>Select from available courses</small>
          </label>
          <select
            name="course_id"
            value={formData.course_id}
            onChange={handleInputChange}
            className="form-select"
            required
            disabled={loadingCourses || backendCourses.length === 0}
          >
            <option value="">-- Select Course --</option>
            {backendCourses.length > 0 ? (
              backendCourses.map(course => (
                <option key={course.id} value={course.id}>
                  {course.name} ({course.branch})
                </option>
              ))
            ) : (
              <option value="" disabled>
                {loadingCourses ? 'Loading courses...' : 'No courses available'}
              </option>
            )}
          </select>
          {loadingCourses && (
            <div className="form-info">
              ⏳ Loading courses from backend...
            </div>
          )}
        </div>

        <div className="form-row">
          {/* Year */}
          <div className="form-group half">
            <label className="form-label">Year</label>
            <select
              name="year"
              value={formData.year}
              onChange={handleInputChange}
              className="form-select"
            >
              <option value="">-- Select Year --</option>
              {yearOptions.map(year => (
                <option key={year} value={year}>Year {year}</option>
              ))}
            </select>
          </div>

          {/* Semester */}
          <div className="form-group half">
            <label className="form-label">Semester</label>
            <select
              name="semester"
              value={formData.semester}
              onChange={handleInputChange}
              className="form-select"
            >
              <option value="">-- Select Semester --</option>
              {semesterOptions.map(sem => (
                <option key={sem} value={sem}>Semester {sem}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Subject */}
        <div className="form-group">
          <label className="form-label">
            Subject <span className="required">*</span>
            <small>(Automatically fetched based on course)</small>
          </label>
          <select
            name="subject_name"
            value={formData.subject_name}
            onChange={handleInputChange}
            className="form-select"
            required
          >
            <option value="">-- Select Subject --</option>
            {subjects.map(subject => (
              <option key={subject} value={subject}>
                {subject}
              </option>
            ))}
          </select>
        </div>

        <div className="form-row">
          {/* Material Type */}
          <div className="form-group half">
            <label className="form-label">Material Type <span className="required">*</span></label>
            <select
              name="material_type"
              value={formData.material_type}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {materialTypes.map(type => (
                <option key={type.value} value={type.value}>
                  {type.label}
                </option>
              ))}
            </select>
          </div>

          {/* Tags */}
          <div className="form-group half">
            <label className="form-label">
              Tags <small>(Comma separated)</small>
            </label>
            <input
              type="text"
              name="tags"
              placeholder="important, unit1, theory, exam"
              value={formData.tags}
              onChange={handleInputChange}
              className="form-input"
            />
          </div>
        </div>

        {/* Summary Preview */}
        {formData.course_id && (
          <div className="summary-preview">
            <h4>📋 Upload Summary</h4>
            <div className="summary-details">
              <p><strong>File:</strong> {file ? file.name : 'No file selected'}</p>
              <p><strong>Title:</strong> {formData.title || 'Not set'}</p>
              <p><strong>Course:</strong> {
                backendCourses.find(c => c.id === parseInt(formData.course_id))?.name || 'Not selected'
              }</p>
              <p><strong>Subject:</strong> {formData.subject_name || 'Not selected'}</p>
              <p><strong>Type:</strong> {materialTypes.find(t => t.value === formData.material_type)?.label || formData.material_type}</p>
            </div>
          </div>
        )}

        {/* Upload Button */}
        <div className="upload-action">
          <button
            onClick={handleUpload}
            disabled={uploading || !file || !formData.title || !formData.course_id || !formData.subject_name}
            className="upload-btn"
          >
            {uploading ? (
              <>
                <span className="spinner"></span>
                ⏳ Uploading...
              </>
            ) : (
              '📤 Upload Material'
            )}
          </button>
          
          <button
            onClick={resetForm}
            type="button"
            className="reset-btn"
            disabled={uploading}
          >
            🔄 Reset Form
          </button>
        </div>

        <div className="admin-note">
          <div className="admin-note-icon">⚠️</div>
          <div className="admin-note-content">
            <strong>Important Note:</strong> All uploads require admin approval. 
            Your file will be visible to students after review. 
            Please ensure all academic details are accurate.
          </div>
        </div>
      </div>
    </div>
  );
};

export default Upload;
